#include <stdio.h>
#include <string.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    char myChoice[10];
    char compChoice[10];
    int myScore = 0, compScore = 0;
    for (int round = 1; round <= T; ++round) {
        scanf("%s %s", myChoice, compChoice);
        int win = 0; // 1 if you win, -1 if computer wins
        if (strcmp(myChoice, "Rock") == 0) {
            if (strcmp(compChoice, "Paper") == 0) win = -1;
            else if (strcmp(compChoice, "Scissors") == 0) win = 1;
            else if (strcmp(compChoice, "Water") == 0) win = -1;
        } else if (strcmp(myChoice, "Paper") == 0) {
            if (strcmp(compChoice, "Rock") == 0) win = 1;
            else if (strcmp(compChoice, "Scissors") == 0) win = -1;
            else if (strcmp(compChoice, "Water") == 0) win = -1;
        } else if (strcmp(myChoice, "Scissors") == 0) {
            if (strcmp(compChoice, "Rock") == 0) win = -1;
            else if (strcmp(compChoice, "Paper") == 0) win = 1;
            else if (strcmp(compChoice, "Water") == 0) win = 1;
        } else if (strcmp(myChoice, "Water") == 0) {
            if (strcmp(compChoice, "Paper") == 0) win = 1;
            else if (strcmp(compChoice, "Scissors") == 0) win = 1;
            else if (strcmp(compChoice, "Rock") == 0) win = -1;
        }
        if (win == 1) {
            ++myScore;
            printf("Round %d: You\n", round);
        } else if (win == -1) {
            ++compScore;
            printf("Round %d: Computer\n", round);
        } else {
            printf("Round %d: Tie\n", round);
        }
    }
    if (myScore > compScore) {
        printf("You won the overall match\n");
    } else if (myScore < compScore) {
        printf("Computer won the overall match\n");
    } else {
        printf("Tie\n");
    }
    return 0;
}

