public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        int myScore = 0, compScore = 0;
        StringBuilder out = new StringBuilder();
        for (int round = 1; round <= T; ++round) {
            String myChoice = br.readLine().trim();
            String compChoice = br.readLine().trim();
            int win = 0; // 1 = you, -1 = computer
            switch (myChoice) {
                case "Rock":
                    if (compChoice.equals("Paper")) win = -1;
                    else if (compChoice.equals("Scissors")) win = 1;
                    else if (compChoice.equals("Water")) win = -1;
                    break;
                case "Paper":
                    if (compChoice.equals("Rock")) win = 1;
                    else if (compChoice.equals("Scissors")) win = -1;
                    else if (compChoice.equals("Water")) win = -1;
                    break;
                case "Scissors":
                    if (compChoice.equals("Rock")) win = -1;
                    else if (compChoice.equals("Paper")) win = 1;
                    else if (compChoice.equals("Water")) win = 1;
                    break;
                case "Water":
                    if (compChoice.equals("Paper") || compChoice.equals("Scissors")) win = 1;
                    else if (compChoice.equals("Rock")) win = -1;
                    break;
            }
            if (win == 1) {
                myScore++;
                out.append("Round ").append(round).append(": You\n");
            } else if (win == -1) {
                compScore++;
                out.append("Round ").append(round).append(": Computer\n");
            } else {
                out.append("Round ").append(round).append(": Tie\n");
            }
        }
        if (myScore > compScore) out.append("You won the overall match\n");
        else if (myScore < compScore) out.append("Computer won the overall match\n");
        else out.append("Tie\n");
        System.out.print(out.toString());
    }
}

