import sys

def winner(me, comp):
    if me == "Rock":
        if comp == "Paper":
            return -1
        if comp == "Scissors":
            return 1
        if comp == "Water":
            return -1
    elif me == "Paper":
        if comp == "Rock":
            return 1
        if comp == "Scissors":
            return -1
        if comp == "Water":
            return -1
    elif me == "Scissors":
        if comp == "Rock":
            return -1
        if comp == "Paper":
            return 1
        if comp == "Water":
            return 1
    elif me == "Water":
        if comp == "Paper" or comp == "Scissors":
            return 1
        if comp == "Rock":
            return -1
    return 0

data = sys.stdin.read().strip().splitlines()
if not data:
    sys.exit()
T = int(data[0])
idx = 1
my_score = 0
comp_score = 0
out_lines = []
for round_num in range(1, T + 1):
    my_choice = data[idx].strip(); idx += 1
    comp_choice = data[idx].strip(); idx += 1
    res = winner(my_choice, comp_choice)
    if res == 1:
        my_score += 1
        out_lines.append(f"Round {round_num}: You")
    elif res == -1:
        comp_score += 1
        out_lines.append(f"Round {round_num}: Computer")
    else:
        out_lines.append(f"Round {round_num}: Tie")
if my_score > comp_score:
    out_lines.append("You won the overall match")
elif my_score < comp_score:
    out_lines.append("Computer won the overall match")
else:
    out_lines.append("Tie")
print("\n".join(out_lines))

